import { Argument, Command, Flag } from "effect/unstable/cli";
import { Console, Effect } from "effect";
import { stringify as stringifyYaml } from "yaml";
import { ScraperService, ScraperServiceLive } from "../services/scraper-service.js";

function encodePlotOutput(plot: unknown, asJson: boolean): string {
  if (asJson) {
    // CLI output only — structured logging would use Effect Schema elsewhere.
    return `${JSON.stringify(plot, null, 2)}\n`;
  }
  return stringifyYaml(plot);
}

/**
 * Parse a saved Idealista listing HTML file into plot fields (YAML or JSON).
 */
export const scrapeIdealistaCommand = Command.make(
  "scrape-idealista",
  {
    htmlPath: Argument.string("html-file"),
    json: Flag.boolean("json").pipe(
      Flag.withDescription("Emit JSON instead of YAML"),
    ),
  },
  ({ htmlPath, json }) =>
    Effect.promise(() => Bun.file(htmlPath).text()).pipe(
      Effect.flatMap((html) =>
        ScraperService.use((svc) =>
          svc.parseIdealistaListingHtml(html).pipe(
            Effect.flatMap((plot) =>
              Console.log(encodePlotOutput(plot, json)),
            ),
          ),
        ),
      ),
      Effect.provide(ScraperServiceLive),
    ),
).pipe(
  Command.withDescription(
    "Extract plot entity fields from a saved Idealista PT listing HTML file",
  ),
);

