const IDEALISTA_ORIGIN = "https://www.idealista.pt";

/** Portuguese mainland districts → coarse macro-region (aligned with seed-style YAML). */
const DISTRICT_TO_REGION: Readonly<Record<string, string>> = {
  Aveiro: "Centro",
  Beja: "Alentejo",
  Braga: "Norte",
  Bragança: "Norte",
  "Castelo Branco": "Centro",
  Coimbra: "Centro",
  Évora: "Alentejo",
  Faro: "Algarve",
  Guarda: "Centro",
  Leiria: "Centro",
  Lisboa: "Lisboa e Vale do Tejo",
  Portalegre: "Alentejo",
  Porto: "Norte",
  Santarém: "Centro",
  Setúbal: "Lisboa e Vale do Tejo",
  "Viana do Castelo": "Norte",
  "Vila Real": "Norte",
  Viseu: "Centro",
};

export class IdealistaHtmlParseError extends Error {
  readonly _tag = "IdealistaHtmlParseError";
  constructor(message: string) {
    super(message);
    this.name = "IdealistaHtmlParseError";
  }
}

