function sliceBalancedBraceObject(html: string, openBraceIndex: number): string | undefined {
  let depth = 0;
  for (let i = openBraceIndex; i < html.length; i++) {
    const c = html[i]!;
    if (c === '"' || c === "'") {
      const q = c;
      i++;
      while (i < html.length) {
        const ic = html[i]!;
        if (ic === "\\") {
          i += 2;
          continue;
        }
        if (ic === q) break;
        i++;
      }
      continue;
    }
    if (c === "{") depth++;
    else if (c === "}") {
      depth--;
      if (depth === 0) return html.slice(openBraceIndex, i + 1);
    }
  }
  return undefined;
}

function extractIdealistaDetailConfigObject(html: string): string | undefined {
  const needle = "var config = ";
  let searchFrom = 0;
  while (true) {
    const idx = html.indexOf(needle, searchFrom);
    if (idx === -1) return undefined;
    const braceStart = html.indexOf("{", idx + needle.length);
    if (braceStart === -1) return undefined;
    const obj = sliceBalancedBraceObject(html, braceStart);
    if (
      obj !== undefined &&
      obj.includes("propertyId:") &&
      obj.includes("detailUrl:")
    ) {
      return obj;
    }
    searchFrom = idx + needle.length;
  }
}

function matchFirstGroup(pattern: RegExp, haystack: string | undefined): string | undefined {
  if (!haystack) return undefined;
  const m = haystack.match(pattern);
  return m?.[1];
}

/** Portuguese Idealista formatting: thousands with `.`, decimals with `,`. */
export function parseIdealistaPtNumber(raw: string): number | undefined {
  const t = raw.replace(/\u00a0/g, " ").replace(/\s+/g, "").replace(/€/g, "").trim();
  const cleaned = t.replace(/\/m².*$/i, "").replace(/m²/gi, "").trim();
  if (!cleaned) return undefined;

  const commaIdx = cleaned.lastIndexOf(",");
  if (
    commaIdx !== -1 &&
    cleaned.length - commaIdx - 1 <= 2 &&
    commaIdx > 0
  ) {
    const whole = cleaned.slice(0, commaIdx).replace(/\./g, "");
    const frac = cleaned.slice(commaIdx + 1);
    const n = Number(`${whole}.${frac}`);
    return Number.isFinite(n) ? n : undefined;
  }

  const dotParts = cleaned.split(".");
  if (
    dotParts.length > 1 &&
    dotParts.every((p, i) => (i === 0 ? p.length > 0 : p.length === 3))
  ) {
    const n = Number(dotParts.join(""));
    return Number.isFinite(n) ? n : undefined;
  }

  const n = Number(cleaned.replace(/\./g, "").replace(",", "."));
  return Number.isFinite(n) ? n : undefined;
}

function decodeHtmlEntities(text: string): string {
  return text
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ");
}

function stripTags(htmlFragment: string): string {
  return decodeHtmlEntities(htmlFragment.replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim());
}

function extractDomText(html: string, classPattern: RegExp): string | undefined {
  const m = html.match(classPattern);
  return m?.[1] !== undefined ? stripTags(m[1]!).trim() || undefined : undefined;
}

function extractMetaContent(html: string, metaPattern: RegExp): string | undefined {
  const m = html.match(metaPattern);
  return m?.[1] !== undefined ? decodeHtmlEntities(m[1]!).trim() || undefined : undefined;
}

function extractDocumentTitle(html: string): string | undefined {
  const m = html.match(/<title[^>]*>([^<]*)<\/title>/i);
  return m?.[1] !== undefined ? decodeHtmlEntities(stripTags(m[1]!)).trim() || undefined : undefined;
}

/** Listing headline from Idealista title / og:title (drops branding suffix). */
function normalizeListingHeadline(raw: string | undefined): string | undefined {
  if (!raw) return undefined;
  const s = raw.replace(/\s*—\s*idealista\s*$/i, "").replace(/\s+idealista\s*$/i, "").trim();
  return s || undefined;
}

/** Area (m²) from meta description e.g. "terreno de 80.000 m², …". */
function extractPlotAreaFromMetaDescription(description: string | undefined): number | undefined {
  if (!description) return undefined;
  const m = description.match(/(?:terreno|lote)\s+de\s+([\d.]+(?:,\d+)?)\s*m²/i);
  return m?.[1] !== undefined ? parseIdealistaPtNumber(m[1]) : undefined;
}

/** `<li class="header-map-list">` crumbs: locality … , often ending `Concelho, Distrito`. */
function extractHeaderMapCrumbs(html: string): string[] {
  const items: string[] = [];
  const re = /<li[^>]*class="[^"]*header-map-list[^"]*"[^>]*>([\s\S]*?)<\/li>/gi;
  let m: RegExpExecArray | null;
  while ((m = re.exec(html)) !== null) {
    const t = stripTags(m[1]!);
    if (t) items.push(t);
  }
  return items;
}

/** Last crumb often `Municipality, District` (e.g. Ourique, Beja). */
function parseDistrictLineFromCrumbs(crumbs: string[]): {
  municipality?: string;
  district?: string;
} {
  if (crumbs.length === 0) return {};
  const last = crumbs[crumbs.length - 1]!;
  const m = last.match(/^([^,]+),\s*(.+)$/);
  if (!m) return {};
  const a = m[1]!.trim();
  const b = m[2]!.trim();
  if (DISTRICT_TO_REGION[b] !== undefined) {
    return { municipality: a, district: b };
  }
  return {};
}

function regionFromDistrict(district: string | undefined): string | undefined {
  if (!district) return undefined;
  return DISTRICT_TO_REGION[district];
}

function listingPrivacyLocationHidden(html: string): boolean {
  return html.includes("no-show-address-feedback-text") &&
    /n[aã]o\s+indicou\s+a\s+localiza[cç][aã]o\s+exata/i.test(html);
}

/** Compose a human location line when street address is withheld. */
function buildApproxAddress(opts: {
  readonly crumbs: string[];
  readonly parishOrLocality?: string;
  readonly municipality?: string;
  readonly district?: string;
  readonly privacyHidden: boolean;
}): string {
  const { crumbs, parishOrLocality, municipality, district, privacyHidden } = opts;
  const crumbLocals =
    crumbs.length >= 2 ? crumbs.slice(0, -1).join(", ") : crumbs.join(", ");
  const minor =
    parishOrLocality !== undefined && municipality !== undefined
      ? `${parishOrLocality}, ${municipality}`
      : municipality ?? "";

  if (!privacyHidden && crumbLocals.length === 0) return "";

  const tail =
    district !== undefined && municipality !== undefined
      ? `${municipality}, ${district}`
      : minor;

  if (crumbLocals.length > 0 && tail.length > 0 && !crumbLocals.includes(tail.split(",")[0]!)) {
    return `${crumbLocals}${tail.length > 0 ? ` · ${tail}` : ""}`;
  }
  if (crumbLocals.length > 0) return crumbLocals;
  return tail;
}

function extractStaticMapCenter(configObj: string | undefined): { lat: number; lng: number } | undefined {
  const src = matchFirstGroup(/multimediaCarrousel:\s*\{[\s\S]*?map:\s*\{[\s\S]*?src:\s*"([^"]+)"/, configObj);
  if (!src) return undefined;
  const center = matchFirstGroup(/[?&]center=([^&]+)/, src);
  if (!center) return undefined;
  const decoded = decodeURIComponent(center.replace(/\+/g, " "));
  const parts = decoded.split(",");
  if (parts.length !== 2) return undefined;
  const lat = Number(parts[0]);
  const lng = Number(parts[1]);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return undefined;
  return { lat, lng };
}

function extractIdForm(configObj: string | undefined): {
  adId?: string;
  buyingPrice?: number;
  locationId?: string;
} {
  if (!configObj) return {};
  const block = matchFirstGroup(/idForm:\s*\{([\s\S]*?)\n\s*\},/, configObj);
  if (!block) return {};
  return {
    adId: matchFirstGroup(/\badId:\s*(\d+)/, block),
    buyingPrice: (() => {
      const s = matchFirstGroup(/\bbuyingPrice:\s*([\d.]+)/, block);
      return s !== undefined ? Number(s) : undefined;
    })(),
    locationId: matchFirstGroup(/\blocationId:\s*"([^"]+)"/, block),
  };
}

function extractCharacteristics(html: string): string[] {
  const section = html.match(
    /<section[^>]*\bid="details"[^>]*class="details-box"[^>]*>([\s\S]*?)<\/section>/,
  );
  if (!section?.[1]) return [];
  const items: string[] = [];
  const liRe = /<li[^>]*>([\s\S]*?)<\/li>/g;
  let m: RegExpExecArray | null;
  while ((m = liRe.exec(section[1])) !== null) {
    const text = stripTags(m[1]!);
    if (text) items.push(text);
  }
  return items;
}

function extractPricePerM2(html: string): number | undefined {
  const block = html.match(
    /<p class="flex-feature squaredmeterprice">([\s\S]*?)<\/p>/,
  );
  if (!block?.[1]) return undefined;
  const span = block[1].match(/<span class="flex-feature-details">([^<]+)<\/span>\s*$/);
  return span?.[1] !== undefined ? parseIdealistaPtNumber(span[1]) : undefined;
}

function extractPlotAreaM2FromInfoFeatures(html: string): number | undefined {
  const block = html.match(/<div class="info-features">([\s\S]*?)<\/div>/);
  if (!block?.[1]) return undefined;
  const m = block[1].match(/([\d.]+(?:,\d+)?)\s*m²/);
  return m?.[1] !== undefined ? parseIdealistaPtNumber(m[1]) : undefined;
}

function parseMunicipalityFromMinorLocation(minor: string | undefined): {
  municipality?: string;
  parishOrLocality?: string;
} {
  if (!minor) return {};
  const m = minor.match(/^([^,]+),\s*(.+)$/);
  if (m) {
    return { parishOrLocality: m[1]!.trim(), municipality: m[2]!.trim() };
  }
  return { municipality: minor.trim() };
}

function extractNumericFactFromCharacteristics(
  characteristics: string[],
  labelPrefix: string,
): number | undefined {
  const line = characteristics.find((l) =>
    l.toLowerCase().startsWith(labelPrefix.toLowerCase()),
  );
  if (!line) return undefined;
  const m = line.match(/([\d.]+(?:,\d+)?)\s*m²/i);
  return m?.[1] !== undefined ? parseIdealistaPtNumber(m[1]) : undefined;
}

function listingNotesFromComment(html: string): string | undefined {
  const block = html.match(
    /<div class="comment"[^>]*>[\s\S]*?<div[^>]*class="adCommentsLanguage[^"]*"[^>]*>[\s\S]*?<p>([\s\S]*?)<\/p>/,
  );
  if (!block?.[1]) return undefined;
  return stripTags(block[1].replace(/<br\s*\/?>/gi, "\n")).trim() || undefined;
}

function combinedListingText(
  characteristics: string[],
  notes: string | undefined,
): string {
  return `${characteristics.join(" | ")} ${notes ?? ""}`.toLowerCase();
}

/** Heuristic: utilities on plot or nearby mains (listing language PT). */
function inferUtilitiesBasicYn(characteristics: string[], blob: string): boolean | undefined {
  if (
    /\b(água|agua|eletricidade|esgoto|saneamento|rede\s+de\s+águas|infraestruturas\s+públicas)\b/i.test(
      blob,
    )
  ) {
    return true;
  }
  if (/\bsem\s+(água|eletricidade|esgotos)\b/i.test(blob)) return false;
  return undefined;
}

/** Seed-style hint when listing mentions ruin / pre-existing construction. */
function inferExistingBuildingUsability(characteristics: string[], notes: string | undefined): string | undefined {
  const blob = `${characteristics.join(" ")} ${notes ?? ""}`.toLowerCase();
  if (/\bru[ií]na\b/.test(blob)) return "renovation";
  if (/\bconstru(ç|c)(aã)o\s+existente\b/.test(blob)) return "renovation";
  return undefined;
}

/** Urban / programme hints for scoring-style raw metrics. */
function inferDevelopmentFlexibility(characteristics: string[], blob: string): string | undefined {
  if (/urbaniz[aá]vel/i.test(blob) && /viabilidade/i.test(blob)) return "high";
  if (/urbaniz[aá]vel/i.test(blob)) return "medium";
  if (/n[aã]o\s+urbaniz/i.test(blob)) return "low";
  return undefined;
}

function inferPotentialTwoUnits(characteristics: string[], blob: string): string | undefined {
  if (/bifamiliar|duas\s+unidades|dois\s+ fogões/i.test(blob)) return "clearly possible";
  if (/unifamiliar|moradia\s+isolada/i.test(blob) && !/bifamiliar/i.test(blob)) {
    return "unlikely";
  }
  return undefined;
}

function inferPlotComplexity(characteristics: string[], blob: string): string | undefined {
  if (/topografia\s+acidentada|declive\s+acentuado/i.test(blob)) return "complex";
  if (/declive|acidentada/i.test(blob)) return "moderate";
  if (/plano|suave/i.test(blob)) return "simple";
  return undefined;
}

function inferSlope(blob: string): string | undefined {
  if (/plano|plan[oí]cie/i.test(blob) && !/declive/i.test(blob)) return "flat/slightly sloped";
  if (/declive/i.test(blob)) return "sloped";
  return undefined;
}

/** Drop keys whose value is undefined (Schema.optionalKey rejects explicit undefined). */
function omitUndefinedKeys<T extends Record<string, unknown>>(record: T): T {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(record)) {
    if (v !== undefined) out[k] = v;
  }
  return out as T;
}

/**
 * Map Idealista saved HTML into a {@link PlotRecord} (validated with domain schema).
 */
export function parseIdealistaListingHtmlToPlotRecord(html: string): PlotRecord {
  const configObj = extractIdealistaDetailConfigObject(html);

  const ogTitle = extractMetaContent(html, /<meta\s+property="og:title"\s+content="([^"]*)"/i);
  const metaDescription = extractMetaContent(
    html,
    /<meta\s+name="description"\s+content="([^"]*)"/i,
  );
  const docTitle = extractDocumentTitle(html);
  const headline = normalizeListingHeadline(ogTitle) ?? normalizeListingHeadline(docTitle);

  const propertyId =
    matchFirstGroup(/\bpropertyId:\s*(\d+)/, configObj) ??
    matchFirstGroup(/name="adId"\s+value="(\d+)"/, html) ??
    matchFirstGroup(/<input[^>]*name="adId"[^>]*value="(\d+)"/, html);

  if (!propertyId) {
    throw new IdealistaHtmlParseError(
      "Could not find Idealista property id (expected inline detail config or adId input).",
    );
  }

  const detailUrl =
    matchFirstGroup(/\bdetailUrl:\s*"([^"]+)"/, configObj) ?? `/imovel/${propertyId}/`;

  const locale = matchFirstGroup(/\blocale:\s*"([^"]+)"/, configObj) ?? "pt";
  const origin =
    locale === "pt" ? IDEALISTA_ORIGIN : `https://www.idealista.${locale}`;
  const referenceUrl = `${origin}${detailUrl.startsWith("/") ? detailUrl : `/${detailUrl}`}`;

  const idForm = extractIdForm(configObj);
  const askingPriceEur =
    idForm.buyingPrice ??
    (() => {
      const fromDom =
        extractDomText(
          html,
          /<span class="info-data-price"><span class="txt-bold">([^<]+)<\/span>\s*€/,
        ) ?? extractDomText(html, /<strong class="price">([^<]+)<\/strong>/);
      return fromDom !== undefined ? parseIdealistaPtNumber(fromDom) : undefined;
    })();

  const titleMain = extractDomText(
    html,
    /<span class="main-info__title-main">([^<]+)<\/span>/,
  );
  const titleMinor = extractDomText(
    html,
    /<span class="main-info__title-minor">([^<]+)<\/span>/,
  );
  const minorParsed = parseMunicipalityFromMinorLocation(titleMinor);

  const headerCrumbs = extractHeaderMapCrumbs(html);
  const { municipality: municipalityFromMap, district } = parseDistrictLineFromCrumbs(headerCrumbs);
  const region = regionFromDistrict(district);

  const municipality = minorParsed.municipality ?? municipalityFromMap;
  const parishOrLocality = minorParsed.parishOrLocality;

  const privacyHidden = listingPrivacyLocationHidden(html);
  const address = buildApproxAddress({
    crumbs: headerCrumbs,
    parishOrLocality,
    municipality,
    district,
    privacyHidden,
  });

  const characteristics = extractCharacteristics(html);
  const plotAreaM2 =
    extractNumericFactFromCharacteristics(
      characteristics,
      "Superfície total do terreno",
    ) ??
    extractNumericFactFromCharacteristics(characteristics, "Superficie mínima") ??
    extractPlotAreaM2FromInfoFeatures(html) ??
    extractPlotAreaFromMetaDescription(metaDescription);

  const buildableAreaM2 = extractNumericFactFromCharacteristics(
    characteristics,
    "Superfície edificável",
  );

  const pricePerM2 = extractPricePerM2(html);

  const mapCenter = extractStaticMapCenter(configObj);

  const typology = matchFirstGroup(/\btypology:\s*"([^"]+)"/, configObj);
  const operation = matchFirstGroup(/\boperation:\s*"([^"]+)"/, configObj);
  const externalRef = matchFirstGroup(/\badExternalReference:\s*"([^"]*)"/, configObj);

  const notes = listingNotesFromComment(html);
  const blob = combinedListingText(characteristics, notes);

  const buildableText = characteristics.join(" ").toLowerCase();
  const buildableYn = buildableText.includes("urbanizável");
  const roadAccessYn = characteristics.some((l) =>
    /acesso\s+por\s+estrada/i.test(l),
  );

  const utilitiesBasicYn = inferUtilitiesBasicYn(characteristics, blob);
  const existingBuildingUsability = inferExistingBuildingUsability(characteristics, notes);
  const developmentFlexibility = inferDevelopmentFlexibility(characteristics, blob);
  const potentialTwoUnits = inferPotentialTwoUnits(characteristics, blob);
  const plotComplexity = inferPlotComplexity(characteristics, blob);
  const slope = inferSlope(blob);

  const displayName =
    headline ??
    titleMain ??
    (municipality !== undefined ? `Terreno — ${municipality}` : `Idealista ${propertyId}`);

  const rawMetrics: Record<string, string | number | string[]> = {
    idealista_property_id: Number(propertyId),
    idealista_locale: locale,
    ...(typology !== undefined ? { idealista_typology: typology } : {}),
    ...(operation !== undefined ? { idealista_operation: operation } : {}),
    ...(idForm.locationId !== undefined
      ? { idealista_location_hierarchy_id: idForm.locationId }
      : {}),
    ...(district !== undefined ? { idealista_district: district } : {}),
    ...(plotAreaM2 !== undefined ? { idealista_plot_area_m2: plotAreaM2 } : {}),
    ...(buildableAreaM2 !== undefined
      ? { idealista_buildable_area_m2: buildableAreaM2 }
      : {}),
    ...(pricePerM2 !== undefined ? { idealista_price_per_m2_eur: pricePerM2 } : {}),
    ...(externalRef !== undefined && externalRef !== ""
      ? { idealista_external_reference: externalRef }
      : {}),
    ...(characteristics.length > 0
      ? { idealista_characteristics: characteristics }
      : {}),
    ...(metaDescription !== undefined ? { idealista_meta_description: metaDescription } : {}),
    ...(ogTitle !== undefined ? { idealista_og_title: ogTitle } : {}),
    ...(headerCrumbs.length > 0 ? { idealista_location_crumbs: headerCrumbs } : {}),

    ...(plotAreaM2 !== undefined ? { plot_size: plotAreaM2 } : {}),
    ...(buildableAreaM2 !== undefined
      ? { permitted_buildable_area: buildableAreaM2 }
      : {}),
    ...(existingBuildingUsability !== undefined
      ? { existing_building_usability: existingBuildingUsability }
      : {}),
    ...(developmentFlexibility !== undefined
      ? { development_flexibility: developmentFlexibility }
      : {}),
    ...(potentialTwoUnits !== undefined ? { potential_two_units: potentialTwoUnits } : {}),
    ...(plotComplexity !== undefined ? { plot_complexity: plotComplexity } : {}),
    ...(slope !== undefined ? { slope } : {}),
  };

  if (parishOrLocality !== undefined) {
    rawMetrics.idealista_parish_or_locality = parishOrLocality;
  }

  const candidate = omitUndefinedKeys({
    id: `idealista-${propertyId}`,
    name: displayName,
    address,
    askingPriceEur,
    koStatus: "none",
    buildableYn: buildableYn ? true : undefined,
    location:
      mapCenter !== undefined
        ? { lat: mapCenter.lat, lng: mapCenter.lng }
        : undefined,
    municipality,
    region,
    notes,
    referenceUrl,
    rawMetrics,
    roadAccessYn: roadAccessYn ? true : undefined,
    utilitiesBasicYn,
  });

  try {
    return decodePlotRecord(candidate);
  } catch (e) {
    throw new IdealistaHtmlParseError(
      `Decoded plot failed schema validation: ${e instanceof Error ? e.message : String(e)}`,
    );
  }
}

