export const scrapeIdealistaCommand = Command.make(
  "scrape-idealista",
  {
    htmlPath: Argument.string("html-file"),
    outputPath: Argument.optional(Argument.string("output-file")),
    format: Flag.choice("format", ["yaml", "json"] as const).pipe(
      Flag.withDefault("yaml"),
      Flag.withDescription("Output serialization (default: yaml)"),
    ),
    json: Flag.boolean("json").pipe(
      Flag.withDescription("Emit JSON (shortcut for --format json)"),
    ),
  },
  ({ htmlPath, format, json, outputPath }) =>
    Effect.promise(() => Bun.file(htmlPath).text()).pipe(
      Effect.flatMap((html) =>
        ScraperService.use((svc) =>
          svc.parseIdealistaListingHtml(html).pipe(
            Effect.flatMap((plot) => {
              const effectiveFormat = json ? "json" : format;
              const body = encodePlotOutput(plot, effectiveFormat);
              return Option.match(outputPath, {
                onNone: () => Console.log(body),
                onSome: (path) =>
                  Effect.promise(() => Bun.write(path, body)).pipe(
                    Effect.asVoid,
                  ),
              });
            }),
          ),
        ),
      ),
      Effect.provide(ScraperServiceLive),
    ),
).pipe(
  Command.withDescription(
    "Extract plot fields from a saved Idealista PT listing HTML file. YAML is the default output; use --format json or --json for JSON. Pass optional output-file to write to disk instead of stdout.",
  ),
);

