/**
 * Idealista number parsing: PT uses `.` thousands and `,` decimals; EN UI uses `,`
 * thousands and `.` decimals (e.g. 10,978 m²).
 */
export function parseIdealistaPtNumber(raw: string): number | undefined {
  const t = raw.replace(/\u00a0/g, " ").replace(/\s+/g, "").replace(/€/g, "").trim();
  const cleaned = t.replace(/\/m².*$/i, "").replace(/m²/gi, "").trim();
  if (!cleaned) return undefined;

  // English-style grouping: 10,978 or 1,234,567 (optional .decimals)
  const enGrouped = cleaned.match(/^(\d{1,3}(?:,\d{3})+)(?:\.(\d+))?$/);
  if (enGrouped) {
    const whole = enGrouped[1]!.replace(/,/g, "");
    const frac = enGrouped[2];
    const n = frac !== undefined ? Number(`${whole}.${frac}`) : Number(whole);
    return Number.isFinite(n) ? n : undefined;
  }

  const commaIdx = cleaned.lastIndexOf(",");

