/** Stable id for deduping Idealista CDN URLs (same asset, different sizes/formats). */
function idealistaPhotoDedupeKey(url: string): string {
  const fileId = url.match(/\/(\d+)\.(?:jpe?g|webp)$/i)?.[1];
  if (fileId !== undefined) return fileId;
  return url.replace(/\?.*$/, "");
}

type MultimediaCarrouselParsed = {
  topPicture?: {
    desktopThumbnailPath?: string;
    mobileThumbnailPath?: string;
    desktopThumbnailWebpPath?: string;
    mobileThumbnailWebpPath?: string;
  };
  multimedias?: Array<{
    type?: string;
    content?: Array<{ src?: string | null; srcWebp?: string | null }>;
  }>;
};

function collectListingPhotoUrls(parsed: MultimediaCarrouselParsed): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  const add = (u: string | null | undefined) => {
    if (!u || typeof u !== "string") return;
    const t = u.trim();
    if (!t.startsWith("http")) return;
    const key = idealistaPhotoDedupeKey(t);
    if (seen.has(key)) return;
    seen.add(key);
    out.push(t);
  };

  const tp = parsed.topPicture;
  if (tp) {
    add(tp.desktopThumbnailPath);
    add(tp.mobileThumbnailPath);
    add(tp.desktopThumbnailWebpPath);
    add(tp.mobileThumbnailWebpPath);
  }

  for (const block of parsed.multimedias ?? []) {
    if (block.type !== "PICTURE") continue;
    for (const item of block.content ?? []) {
      add(item.src ?? undefined);
      add(item.srcWebp ?? undefined);
    }
  }

  return out;
}

/** Gallery image URLs from inline config `multimediaCarrousel` JSON (cover-oriented order). */
function extractIdealistaListingImageUrls(configObj: string | undefined): string[] {
  if (!configObj) return [];
  const needle = "multimediaCarrousel:";
  const idx = configObj.indexOf(needle);
  if (idx === -1) return [];
  const braceStart = configObj.indexOf("{", idx + needle.length);
  if (braceStart === -1) return [];
  const jsonSlice = sliceBalancedBraceObject(configObj, braceStart);
  if (!jsonSlice) return [];
  try {
    const parsed = JSON.parse(jsonSlice) as MultimediaCarrouselParsed;
    const urls = collectListingPhotoUrls(parsed);
    return urls;
  } catch {
    return [];
  }
