import { Button } from "@portugal/ui";
import { cn } from "@portugal/ui-lib";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { useCallback, useEffect, useState } from "react";

export type PlotPhotoCarouselProps = {
	images: readonly string[];
	alt: string;
	className?: string;
};

export function PlotPhotoCarousel({
	images,
	alt,
	className,
}: PlotPhotoCarouselProps) {
	const slides = images.map((u) => u.trim()).filter((u) => u.length > 0);
	const [index, setIndex] = useState(0);

	useEffect(() => {
		setIndex(0);
	}, [slides.join("|")]);

	const slideCount = slides.length;
	const activeIndex =
		slideCount === 0 ? 0 : Math.min(Math.max(0, index), slideCount - 1);

	const go = useCallback(
		(delta: number) => {
			if (slideCount === 0) return;
			setIndex((i) => (i + delta + slideCount) % slideCount);
		},
		[slideCount],
	);

	const onKeyDown = useCallback(
		(event: React.KeyboardEvent) => {
			if (event.key === "ArrowLeft") {
				event.preventDefault();
				go(-1);
			}
			if (event.key === "ArrowRight") {
				event.preventDefault();
				go(1);
			}
		},
		[go],
	);

	if (slides.length === 0) {
		return (
			<div
				className={cn(
					"relative flex aspect-[16/10] w-full items-center justify-center overflow-hidden rounded-2xl bg-muted text-sm text-muted-foreground ring-1 ring-border/20",
					className,
				)}
			>
				No photos
			</div>
		);
	}

	const current = slides[activeIndex] ?? slides[0];

	return (
		<div
			className={cn(
				"group relative aspect-[16/10] w-full overflow-hidden rounded-2xl bg-muted ring-1 ring-border/20",
				className,
			)}
			role="region"
			aria-roledescription="carousel"
			aria-label={`Photos of ${alt}`}
			tabIndex={0}
			onKeyDown={onKeyDown}
		>
			<img
				src={current}
				alt={`${alt} — photo ${activeIndex + 1} of ${slides.length}`}
				className="size-full object-cover"
				loading="lazy"
			/>
			{slides.length > 1 ? (
				<>
					<Button
						type="button"
						variant="secondary"
						size="icon"
						className="absolute left-2 top-1/2 z-10 -translate-y-1/2 shadow-md"
						aria-label="Previous photo"
						onClick={() => go(-1)}
					>
						<ChevronLeft className="size-5" />
					</Button>
					<Button
						type="button"
						variant="secondary"
						size="icon"
						className="absolute right-2 top-1/2 z-10 -translate-y-1/2 shadow-md"
						aria-label="Next photo"
						onClick={() => go(1)}
					>
						<ChevronRight className="size-5" />
					</Button>
					<div className="pointer-events-none absolute inset-x-0 bottom-2 flex justify-center gap-1.5">
						{slides.map((_, i) => (
							<button
								key={`dot-${i}-${slides[i]?.slice(-24)}`}
								type="button"
								tabIndex={-1}
								className={cn(
									"pointer-events-auto h-2 w-2 rounded-full ring-2 ring-black/25 transition-colors",
									i === activeIndex ? "bg-white" : "bg-white/45",
								)}
								aria-label={`Go to photo ${i + 1}`}
								aria-current={i === activeIndex}
								onClick={() => setIndex(i)}
							/>
						))}
					</div>
				</>
			) : null}
		</div>
	);
}

