import {
	Button,
	Dialog,
	DialogContent,
	DialogTitle,
} from "@portugal/ui";
import { cn } from "@portugal/ui-lib";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { useCallback, useState, type KeyboardEvent } from "react";

export type PlotPhotoCarouselProps = {
	images: readonly string[];
	alt: string;
	className?: string;
};

type CarouselChromeProps = {
	slideCount: number;
	activeIndex: number;
	go: (delta: number) => void;
	setIndex: (i: number) => void;
	/** Lightbox uses higher contrast controls on dark backdrop */
	variant: "inline" | "lightbox";
};

function CarouselChrome({
	slideCount,
	activeIndex,
	go,
	setIndex,
	variant,
}: CarouselChromeProps) {
	if (slideCount <= 1) return null;

	const btnClass =
		variant === "lightbox"
			? "border-white/20 bg-black/50 text-white hover:bg-black/70"
			: "";

	const dotRing =
		variant === "lightbox" ? "ring-white/40" : "ring-black/25";

	const dotActive = variant === "lightbox" ? "bg-white" : "bg-white";
	const dotIdle =
		variant === "lightbox" ? "bg-white/45" : "bg-white/45";

	return (
		<>
			<Button
				type="button"
				variant="secondary"
				size="icon"
				className={cn(
					"absolute left-2 top-1/2 z-20 -translate-y-1/2 shadow-md",
					btnClass,
				)}
				aria-label="Previous photo"
				onClick={(e) => {
					e.stopPropagation();
					go(-1);
				}}
			>
				<ChevronLeft className="size-5" />
			</Button>
			<Button
				type="button"
				variant="secondary"
				size="icon"
				className={cn(
					"absolute right-2 top-1/2 z-20 -translate-y-1/2 shadow-md",
					btnClass,
				)}
				aria-label="Next photo"
				onClick={(e) => {
					e.stopPropagation();
					go(1);
				}}
			>
				<ChevronRight className="size-5" />
			</Button>
			<div className="pointer-events-none absolute inset-x-0 bottom-2 z-20 flex justify-center gap-1.5">
				{Array.from({ length: slideCount }, (_, i) => (
					<button
						key={i}
						type="button"
						tabIndex={-1}
						className={cn(
							"pointer-events-auto h-2 w-2 rounded-full ring-2 transition-colors",
							dotRing,
							i === activeIndex ? dotActive : dotIdle,
						)}
						aria-label={`Go to photo ${i + 1}`}
						aria-current={i === activeIndex}
						onClick={(e) => {
							e.stopPropagation();
							setIndex(i);
						}}
					/>
				))}
			</div>
		</>
	);
}

export function PlotPhotoCarousel({
	images,
	alt,
	className,
}: PlotPhotoCarouselProps) {
	const slides = images.map((u) => u.trim()).filter((u) => u.length > 0);
	const [index, setIndex] = useState(0);
	const [lightboxOpen, setLightboxOpen] = useState(false);

	const slideCount = slides.length;
	const activeIndex =
		slideCount === 0 ? 0 : Math.min(Math.max(0, index), slideCount - 1);

	const go = useCallback(
		(delta: number) => {
			if (slideCount === 0) return;
			setIndex((i) => (i + delta + slideCount) % slideCount);
		},
		[slideCount],
	);

	const onInlineKeyDown = useCallback(
		(event: KeyboardEvent<HTMLDivElement>) => {
			if (event.key === "ArrowLeft") {
				event.preventDefault();
				go(-1);
			}
			if (event.key === "ArrowRight") {
				event.preventDefault();
				go(1);
			}
		},
		[go],
	);

	const onLightboxKeyDown = useCallback(
		(event: KeyboardEvent<HTMLDivElement>) => {
			if (event.key === "ArrowLeft") {
				event.preventDefault();
				go(-1);
			}
			if (event.key === "ArrowRight") {
				event.preventDefault();
				go(1);
			}
		},
		[go],
	);

	if (slides.length === 0) {
		return (
			<div
				className={cn(
					"relative flex aspect-[16/10] w-full items-center justify-center overflow-hidden rounded-2xl bg-muted text-sm text-muted-foreground ring-1 ring-border/20",
					className,
				)}
			>
				No photos
			</div>
		);
	}

	const current = slides[activeIndex] ?? slides[0];

	return (
		<>
			<div
				className={cn(
					"group relative aspect-[16/10] w-full overflow-hidden rounded-2xl bg-muted ring-1 ring-border/20",
					className,
				)}
				role="region"
				aria-roledescription="carousel"
				aria-label={`Photos of ${alt}`}
				tabIndex={0}
				onKeyDown={onInlineKeyDown}
			>
				<button
					type="button"
					className="absolute inset-0 z-0 cursor-zoom-in rounded-2xl border-0 bg-transparent p-0 text-left outline-none ring-inset ring-transparent transition-[box-shadow] hover:ring-2 hover:ring-ring/40 focus-visible:ring-2 focus-visible:ring-ring"
					aria-label={`Open fullscreen gallery — photo ${activeIndex + 1} of ${slides.length}`}
					onClick={() => setLightboxOpen(true)}
				/>
				<div className="pointer-events-none relative z-[1] flex h-full w-full items-center justify-center p-2">
					<img
						src={current}
						alt={`${alt} — photo ${activeIndex + 1} of ${slides.length}`}
						className="max-h-full max-w-full object-contain"
						loading="lazy"
						decoding="async"
						sizes="(max-width: 640px) 100vw, min(960px, 85vw)"
					/>
				</div>
				<CarouselChrome
					slideCount={slideCount}
					activeIndex={activeIndex}
					go={go}
					setIndex={setIndex}
					variant="inline"
				/>
			</div>

			<Dialog open={lightboxOpen} onOpenChange={setLightboxOpen}>
				<DialogContent
					showCloseButton
					aria-describedby={undefined}
					onKeyDown={onLightboxKeyDown}
					className={cn(
						"fixed! inset-0! top-0! left-0! z-[100] flex h-[100dvh]! max-h-[100dvh]! w-screen! max-w-none! translate-none! flex-col gap-0 rounded-none border-0 bg-black p-3 pt-14 pb-6 text-white shadow-none ring-0 sm:max-w-none!",
						"[&_[data-slot=dialog-close]]:text-white [&_[data-slot=dialog-close]]:hover:bg-white/15",
					)}
				>
					<DialogTitle className="sr-only">
						{alt} — fullscreen photo gallery
					</DialogTitle>
					<p className="absolute left-3 top-3 z-30 max-w-[calc(100%-5rem)] truncate text-xs text-white/80">
						{activeIndex + 1} / {slides.length}
						{slides.length > 1 ? (
							<span className="text-white/50"> · Arrow keys · Esc to close</span>
						) : null}
					</p>
					<div className="relative flex min-h-0 flex-1 flex-col">
						<div className="flex min-h-0 flex-1 items-center justify-center overflow-auto px-1">
							<img
								src={current}
								alt={`${alt} — photo ${activeIndex + 1} of ${slides.length}, full view`}
								className="max-h-[calc(100dvh-7rem)] max-w-full object-contain"
								decoding="async"
								sizes="100vw"
							/>
						</div>
						<CarouselChrome
							slideCount={slideCount}
							activeIndex={activeIndex}
							go={go}
							setIndex={setIndex}
							variant="lightbox"
						/>
					</div>
				</DialogContent>
			</Dialog>
		</>
	);
}

